linearIds;"}

{"code":"// Fetch all 9 Linear issues in parallel
const uniqueIds = [...new Set(linearIds.map(x => x.linearId))];
const linearIssues = {};
for (const id of uniqueIds) {
  const issue = linear__get_issue({ id });
  linearIssues[id] = issue;
}
// Show states
Object.entries(linearIssues).map(([id, issue]) => ({ id, state: issue.state }));"}

{"code":"// Filter: Linear issue state is NOT "done"
const results = linearIds.filter(({ linearId }) => linearIssues[linearId].state !== "done");
const summary = results.map(({ pr, repo, linearId }) => ({
  prNumber: pr,
  repo,
  linearIssue: linearId,
  linearState: linearIssues[linearId].state
}));
({ total: summary.length, details: summary });"}
